import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def calculate_penalty_based_on_time_window(arrival_time, time_window):
        start_window, end_window = time_window
        if arrival_time < start_window:
            return (start_window - arrival_time) * 3  # Increased waiting penalty
        elif arrival_time > end_window:
            return (arrival_time - end_window) * 30  # Increased late penalty
        return 0  # No penalty if within the time window

    def calculate_proximity_score(all_truck_positions, target_position):
        return sum(calculate_distance(pos, target_position) for pos in all_truck_positions) / len(all_truck_positions)

    scores = []
    total_customers = len(unvisited_customers) + len(all_truck_pos)  # considering all trucks are initially at a customer
    weight_adjustment_factor = 1 / (total_customers - len(unvisited_customers) + 1)

    for idx, customer in enumerate(unvisited_customers):
        travel_time_to_customer = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time_to_customer = current_time + travel_time_to_customer
        penalty_time = calculate_penalty_based_on_time_window(arrival_time_to_customer, time_windows[idx])
        proximity_score = calculate_proximity_score(all_truck_pos, customer)

        # Dynamic weight adjustment
        distance_weight = 1.0
        penalty_weight = 2.0 * weight_adjustment_factor
        proximity_weight = 0.5 * (1 - weight_adjustment_factor)

        score = (distance_weight * travel_time_to_customer) + (penalty_weight * penalty_time) - proximity_weight * proximity_score
        scores.append(score)

    best_node = np.argmin(scores)
    return best_node
